1	const PROCESSING_FEE = 5;
2	const DEDUCTIBLE = 100;
3	const CAP_MULTIPLIER = 2;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const INSURANCE_VALUE: Record<string, number> = {
15	  sword: 1000,
16	  amulet: 600,
17	  staff: 800,
18	  potion: 400,
19	  rune: 250,
20	  moonstone: 250,
21	};
22	
23	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
24	type Customer = { yearsWithMHPCO: number };
25	type QuoteStep = { op: "quote"; items: Item[] };
26	type Damage = { itemType: string; amount: number };
27	type Incident = { cause: string; damages: Damage[] };
28	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
29	type Step = QuoteStep | ClaimStep;
30	type Scenario = { customer: Customer; steps: Step[] };
31	
32	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type];
33	
34	const COMPONENT_BLOCK_SIZE = 3;
35	const COMPONENT_BLOCK_PREMIUM = 60;
36	
37	const sumBy = <T>(xs: T[], f: (x: T) => number): number =>
38	  xs.reduce((sum, x) => sum + f(x), 0);
39	
40	const groupByType = (items: Item[]): Item[][] => {
41	  const groups = new Map<string, Item[]>();
42	  for (const item of items) {
43	    const group = groups.get(item.type) ?? [];
44	    group.push(item);
45	    groups.set(item.type, group);
46	  }
47	  return [...groups.values()];
48	};
49	
50	const basePremiumForGroup = (group: Item[]): number =>
51	  group.length === COMPONENT_BLOCK_SIZE
52	    ? COMPONENT_BLOCK_PREMIUM
53	    : sumBy(group, basePremiumFor);
54	
55	const totalBasePremium = (items: Item[]): number =>
56	  sumBy(groupByType(items), basePremiumForGroup);
57	
58	const CURSE_SURCHARGE_RATE = 0.5;
59	const HIGH_ENCHANTMENT_RATE = 0.3;
60	const HIGH_ENCHANTMENT_THRESHOLD = 5;
61	const FIRST_INSURANCE_RATE = 0.1;
62	const LOYALTY_DISCOUNT_RATE = -0.2;
63	const LOYALTY_YEARS_THRESHOLD = 2;
64	const FOLLOW_UP_DISCOUNT_RATE = -0.15;
65	
66	type PolicyContext = { customer: Customer; isFollowUp: boolean };
67	
68	const isCursed = (item: Item): boolean => item.cursed === true;
69	const isHighlyEnchanted = (item: Item): boolean =>
70	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
71	
72	type Modifier<T> = { applies: (subject: T) => boolean; rate: number };
73	
74	const sumApplicableRates = <T>(modifiers: Modifier<T>[], subject: T): number =>
75	  sumBy(modifiers, ({ applies, rate }) => (applies(subject) ? rate : 0));
76	
77	const ITEM_SURCHARGES: Modifier<Item>[] = [
78	  { applies: isCursed, rate: CURSE_SURCHARGE_RATE },
79	  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_RATE },
80	];
81	
82	const isFirstInsurance = (_ctx: PolicyContext): boolean => true;
83	const isLoyalCustomer = (ctx: PolicyContext): boolean =>
84	  ctx.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
85	const isFollowUpContract = (ctx: PolicyContext): boolean => ctx.isFollowUp;
86	
87	const POLICY_MODIFIERS: Modifier<PolicyContext>[] = [
88	  { applies: isFirstInsurance, rate: FIRST_INSURANCE_RATE },
89	  { applies: isLoyalCustomer, rate: LOYALTY_DISCOUNT_RATE },
90	  { applies: isFollowUpContract, rate: FOLLOW_UP_DISCOUNT_RATE },
91	];
92	
93	const policyAdjustment = (baseTotal: number, ctx: PolicyContext): number =>
94	  baseTotal * sumApplicableRates(POLICY_MODIFIERS, ctx);
95	
96	const itemSurchargeFor = (item: Item): number =>
97	  basePremiumFor(item) * sumApplicableRates(ITEM_SURCHARGES, item);
98	
99	const itemSurchargesTotal = (items: Item[]): number =>
100	  sumBy(items, itemSurchargeFor);
101	
102	const premiumFor = (items: Item[], ctx: PolicyContext): number => {
103	  const baseTotal = totalBasePremium(items);
104	  return Math.ceil(
105	    baseTotal +
106	      itemSurchargesTotal(items) +
107	      policyAdjustment(baseTotal, ctx) +
108	      PROCESSING_FEE,
109	  );
110	};
111	
112	const insuranceSumFor = (items: Item[]): number =>
113	  sumBy(items, (item) => INSURANCE_VALUE[item.type]);
114	
115	const payoutForDamage = (damage: Damage): number => damage.amount - DEDUCTIBLE;
116	
117	const claimResultFor = (
118	  step: ClaimStep,
119	  steps: Step[],
120	): { payout: number; remainingCap: number } => {
121	  const policy = steps[step.policy] as QuoteStep;
122	  const cap = insuranceSumFor(policy.items) * CAP_MULTIPLIER;
123	  const payout = sumBy(step.incident.damages, payoutForDamage);
124	  return { payout, remainingCap: cap - payout };
125	};
126	
127	const quoteResultFor = (step: QuoteStep, ctx: PolicyContext) => ({
128	  premium: premiumFor(step.items, ctx),
129	});
130	
131	export const runScenario = (input: unknown): unknown => {
132	  const scenario = input as Scenario;
133	  return {
134	    results: scenario.steps.map((step, index) =>
135	      step.op === "quote"
136	        ? quoteResultFor(step, { customer: scenario.customer, isFollowUp: index > 0 })
137	        : claimResultFor(step, scenario.steps),
138	    ),
139	  };
140	};
